const { z } = require('zod');

const UserQuerySchema = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(10),
  search: z.string().trim().max(50).optional(),
});

app.get('/users', (req, res, next) => {
  const parsed = UserQuerySchema.safeParse(req.query);
  if (!parsed.success) {
