// Centralized error middleware
app.use((err, req, res, next) => {
  console.error(err); // ideally a real logger (pino/winston), not console
  const status = err.status || 500;
  // Never leak err.stack or err.message to clients in production
  res.status(status).json({ error: status === 500 ? 'Internal server error' : err.message });
});

const server = app.listen(3000, () => console.log('Server running on port 3000'));
server.on('error', (err) => { console.error('Listen error:', err); process.exit(1); });

process.on('unhandledRejection', (reason) => console.error('Unhandled rejection:', reason));
process.on('uncaughtException', (err) => { console.error('Uncaught:', err); process.exit(1); });
```

## 2. Input validation

Currently no route accepts user input, but the patterns are missing for when they will. Recommendations for when you add params/bodies:

- Use a schema validator (`zod`, `joi`, or `express-validator`) — never trust `req.body`, `req.query`, `req.params`, or headers.
