const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const { query, validationResult } = require('express-validator');

const app = express();
const PORT = process.env.PORT || 3000;

// 1. Security headers (HSTS, CSP, X-Frame-Options, etc.)
app.use(helmet());

// 2. Restrictive CORS — don't use the default wildcard
app.use(cors({
  origin: process.env.ALLOWED_ORIGIN || 'https://example.com',
  methods: ['GET'],
}));

// 3. Rate limiting to mitigate brute-force / DoS
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// 4. Body size limits (prevents memory-exhaustion DoS)
app.use(express.json({ limit: '10kb' }));

// 5. Disable the X-Powered-By header (fingerprinting)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (req, res) => {
  // No sensitive info — safe to expose
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

