const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '100kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (req, res) => {
  res.json([/* ... */]);
});

app.use((req, res) => res.status(404).json({ error: 'Not found' }));
app.use((err, req, res, next) => {
  console.error(err);
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

const port = Number(process.env.PORT) || 3000;
const server = app.listen(port, () => console.log(`Server on :${port}`));
server.on('error', (err) => { console.error(err); process.exit(1); });
```

## Priorities
1. **High**: central error handler, `x-powered-by` disable, JSON body size limit, auth on `/users`.
2. **Medium**: helmet, rate limiting, 404 handler, `process.env.PORT`.
3. **Low (as surface grows)**: schema validation library, structured logging with redaction, CORS allowlist.

